mapper.select:
    select  * from
	(select  a.*,rowNum m_rowNum  from
	(select
	   to_char(tfa_alarm_cpm_hq_detail.first_result , 'yyyy-mm-dd hh24:mi:ss') a_cloumn_00,
	   tfa_alarm_cpm_hq_detail.nms_name a_cloumn_01,
	   meta_objects.ZH_NAME  a_cloumn_02,
	   tfa_alarm_cpm_hq_detail.eqp_label a_cloumn_03,
	   tfa_alarm_cpm_hq_detail.org_severity a_cloumn_04,
	   tfa_alarm_cpm_hq_detail.alarm_title_text   a_cloumn_05,
	   to_char(tfa_alarm_cpm_hq_detail.event_time,'yyyy-mm-dd hh24:mi:ss') a_cloumn_06,
	   to_char(tfa_alarm_cpm_hq_detail.cancel_time,'yyyy-mm-dd hh24:mi:ss')   a_cloumn_07
  from tfa_alarm_cpm_hq_detail tfa_alarm_cpm_hq_detail,(select ZH_NAME,OBJECT_CLASS from meta_objects where object_class in(508,1521,502,905,901,1514,506,1520)) meta_objects
		 where first_result =to_date(#{first_result},'yyyy-MM-dd HH24:mi:ss')
		 and eqp_object_class = #{eqp_object_class}
		 and nms_name =  #{g1}
		 and eqp_label =  #{g3}
		 and alarm_title_text = #{g4}
 and tfa_alarm_cpm_hq_detail.eqp_object_class =meta_objects.object_class
		${DetailWhereCondition}
	)a
	)
Where m_rowNum > ${BegeinIndex} and m_rowNum <= ${EndIndex}
